INSERT INTO `itinerary_days` VALUES (21,2,1,'Đà Nẵng - Đà Lạt','3 bữa ăn','<p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Quý khách tập trung tại&nbsp;<strong style=\"box-sizing: inherit;\">Vietravel</strong>, xe đưa đoàn khởi hành đi Đà Lạt. Trên đường đi Quý khách ghé tham quan:</p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Thác Bobla -&nbsp;</strong>đẹp như một bức tranh thiên nhiên với dòng thác nguyên sơ, hùng vĩ cao hơn 40m, rộng hơn 20m, cùng cảnh quan được tôn tạo tuyệt đẹp, lưu giữ nhiều cây cổ thụ hàng trăm năm tuổi, phía xa hút tầm mắt là những đồi chè, cà phê xanh mát.</li><li style=\"box-sizing: inherit;\">T<strong style=\"box-sizing: inherit;\">hiền Viện Trúc Lâm -&nbsp;</strong>một trong những thiền viện lớn nhất của Lâm Đồng với kiến trúc dân tộc truyền thống kết hợp hài hòa với cấu trúc đương đại Á Đông đặc sắc..</li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Tiếp tục hành trình, Quý khách đến với thành phố sương mù&nbsp;<strong style=\"box-sizing: inherit;\">“Đà Lạt mộng mơ”</strong>&nbsp;nhận phòng nghỉ ngơi và dùng bữa tối tại nhà hàng địa phương.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Buổi tối, Quý khách tự do dạo phố thưởng thức ẩm thực nổi tiếng phố núi: Lẩu gà lá é Tao Ngộ, Lẩu bò quán Gỗ, Bánh ướt lòng gà, Ốc nhồi thịt, Xe lẩu buffet, Ngói BBQ …<strong style=\"box-sizing: inherit;\">&nbsp;(chi phí tự túc).</strong></p><p class=\"ql-align-right\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: right; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">Nghỉ đêm tại Đà Lạt</strong></p>',0),(22,2,2,'Đà Lạt - Thành phố ngàn hoa','3 bữa ăn','<p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Sau khi dùng bữa sáng tại khách sạn, Quý khách khởi hành đi tham quan:</span></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit; text-align: justify;\"><p style=\"box-sizing: inherit; line-height: 2.5rem; margin: 1rem; font-family: inherit !important;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">Đường Hầm Đất Sét -</strong>&nbsp;nổi tiếng với những tác phẩm điêu khắc bằng đất nung ấn tượng như: Ga xe lửa, Dinh Bảo Đại, Nhà thờ Con Gà, “Hồ vô cực” thu hút nhiều du khách đến tham quan.</span></p></li></ul><p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Đoàn dùng bữa trưa và trở về khách sạn nghỉ ngơi. Buổi chiều, Quý khách tiếp tục tham quan:</span></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit; text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">KDL Cao Nguyên Hoa -</strong>&nbsp;nơi bảo tồn đa dạng sinh học đặc biệt là các lòai hoa thân gỗ. Đến đây Quý khách sẽ được trải nghiệm:</span><ul style=\"box-sizing: inherit;\"><li style=\"box-sizing: inherit;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Thư giãn tại quán&nbsp;<strong style=\"box-sizing: inherit;\">Seven-T Coffee</strong>&nbsp;nằm giữa rừng thông, bể bơi vô cực giữa rừng nhiệt đới&nbsp;</span></li><li style=\"box-sizing: inherit;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Tham gia trò chơi&nbsp;<strong style=\"box-sizing: inherit;\">Đà Lạt Swing -</strong>&nbsp;“xích đu tiên” lớn nhất Việt Nam</span></li><li style=\"box-sizing: inherit;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">Rose Garden&nbsp;</strong>- Vườn hoa hồng với hàng trăm gốc hồng ngoại, hồng nội, hồng cổ thụ quý&nbsp;</span></li><li style=\"box-sizing: inherit;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Thoả sức chụp hình với&nbsp;<strong style=\"box-sizing: inherit;\">dàn siêu xe</strong>&nbsp;cực chất, đồi mai anh đào, đồi huệ sông nile, đồi hoa sim tím, đồi hoa hoàng yến,…</span></li></ul></li><li style=\"box-sizing: inherit; text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">Trang trại rau và hoa Vạn Thành -</strong>&nbsp;khám phá quy trình trồng những loại nông sản và thỏa sức chụp hình với các vườn hoa hồng, cẩm chướng, lily, đồng tiền, cẩm tú cầu hay các vườn cà chua, bí khổng lồ, dưa Pepino, dâu và các loại rau trồng thủy canh (tùy theo mùa).&nbsp;</span></li><li style=\"box-sizing: inherit; text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Mua sắm đặc sản Đà Lạt tại&nbsp;<strong style=\"box-sizing: inherit;\">cơ sở mứt Thanh Nhu</strong>&nbsp;các loại trái cây sấy giòn, sấy dẻo, nước cốt dâu tằm - dâu tươi, trà atiso, trà hoa, ...</span></li></ul><p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Quý khách dùng bữa tối tại nhà hàng và tự do nghỉ ngơi, khám phá Đà Lạt về đêm.</span></p><p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: right;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">Nghỉ đêm tại Đà Lạt</strong></span></p>',1),(25,3,1,'Bà Nà - Cầu Vàng','sáng, tối','<p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Dùng bữa sáng tại khách sạn. Quý khách khởi hành đi tham quan:</p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Khu du lịch Bà Nà&nbsp;</strong><strong style=\"box-sizing: inherit; color: rgb(0, 102, 204);\"><em style=\"box-sizing: inherit;\">(chi phí cáp treo &amp; ăn trưa tự túc)</em></strong><strong style=\"box-sizing: inherit;\">:</strong>&nbsp;tận hưởng không khí se lạnh của Đà Lạt tại miền Trung, đoàn tự do tham quan Chùa Linh Ứng, Hầm Rượu Debay, vườn hoa Le Jardin D’Amour, Khu Tâm linh mới của Bà Nà viếng Đền Lĩnh Chúa Linh Từ, khu vui chơi Fantasy Park, tự do chụp hình tại&nbsp;<strong style=\"box-sizing: inherit;\">Cầu Vàng</strong>&nbsp;điểm tham quan siêu hot tại Bà Nà…&nbsp;<strong style=\"box-sizing: inherit;\">(Ăn trưa tại Bà Nà tự túc)</strong></li><li style=\"box-sizing: inherit;\">Sau đó đoàn tiếp tục tham quan vui chơi đến giờ xuống cáp.</li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Buổi chiều đoàn di chuyển về lại trung tâm TP Đà Nẵng ăn tối và nhận phòng nghỉ ngơi.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><em style=\"box-sizing: inherit;\">Buổi tối quý khách tự do hòa mình vào nhịp sống nhộn nhịp của các khu chợ đêm nổi tiếng Đà Thành như Helio, Sơn Trà</em></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><em style=\"box-sizing: inherit;\">Quý khách có thể trải nghiệm du thuyền Poseidon sang trọng bậc nhất sông Hàn (chi phi tự túc).</em></li><li style=\"box-sizing: inherit;\"><em style=\"box-sizing: inherit;\">Hoặc chiêm ngưỡng khung cảnh mê hoặc của Hàn Giang về đêm cùng những cây cầu mang tính biểu tượng, mãn nhãn với màn trình diễn rồng phun lửa từ góc nhìn độc đáo vào dịp cuối tuần.</em></li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">Nghỉ đêm tại Đà Nẵng</strong></p>',0),(26,3,2,'Đà Nẵng','sáng','<p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Dùng bữa sáng tại khách sạn. Quý khách tự do dạo phố cảm nhận không khí trong lành và khung cảnh yên bình vào sáng sớm.</p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Mua sắm đặc sản phố biển tại Giao Mart hoặc Quà Đà Nẵng Thiên Phú:</strong>&nbsp;với hơn 2000 sản phẩm đặc sản Đà Nẵng, Miền Trung và các vùng miền lân cận, nổi bật nhất là chả bò, bò khô, mực rim me, mực khô, ghẹ sữa sốt và đầy đủ các loại khô cá,...</li></ul>',1),(31,4,1,'Khám phá quần thể Chùa Bà','sáng, trưa','<p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Hướng dẫn viên và xe đón Quý khách tại Vietravel (190 Pasteur, Quận 3, TP.HCM) khởi hành đi&nbsp;<strong style=\"box-sizing: inherit;\">Tây Ninh</strong>. Sau khi ăn sáng, đoàn dừng chân chiêm ngưỡng<strong style=\"box-sizing: inherit;\">&nbsp;Tòa Thánh Tây Ninh</strong>&nbsp;- một quần thể kiến trúc độc đáo, tìm hiểu về Đạo Cao Đài - tôn giáo có xuất xứ tại Việt Nam.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Đến&nbsp;<strong style=\"box-sizing: inherit;\">Quần thể danh thắng núi Bà Đen</strong>&nbsp;- nổi tiếng với cảnh sắc thiên nhiên hoang sơ và quần thể kiến trúc tâm linh lâu đời. Bên cạnh đó, du khách có thể check-in<strong style=\"box-sizing: inherit;\">&nbsp;nhà ga cáp treo lớn nhất thế giới</strong>, với tuyến cáp treo hiện đại hành trình chiêm bái và chinh phục ngọn núi cao nhất Nam Bộ của du khách thập phương trở nên dễ dàng hơn bao giờ hết.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit; color: rgb(231, 76, 60);\">Chương trình đã bao gồm vé tham quan 3 tuyến cáp treo Chùa Hang - Tâm An - Vân Sơn (*)</strong></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">Tuyến</strong>&nbsp;<strong style=\"box-sizing: inherit;\">cáp treo Chùa Hang</strong>&nbsp;đến&nbsp;<strong style=\"box-sizing: inherit;\">Quần Thể Tâm Linh Chùa Bà:</strong>&nbsp;ở độ cao 350m giữa lưng chừng núi là quần thể kiến trúc hang động, với hàng chục nơi thờ tự tạo nên sự tôn nghiêm giữa núi rừng. Nổi bật nhất là&nbsp;<strong style=\"box-sizing: inherit;\">Linh Sơn Tiên Thạch Tự (chùa Bà)&nbsp;</strong>- ngôi chùa cổ xưa nhất ở Tây Ninh, gắn liền với đời sống tín ngưỡng của người dân địa phương và cũng là mốc son ghi dấu thời điểm Phật giáo đến Tây Ninh.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Tiếp tục theo&nbsp;<strong style=\"box-sizing: inherit;\">tuyến cáp treo Tâm An</strong>, đoàn&nbsp;<strong style=\"box-sizing: inherit;\">chinh phục đỉnh núi Bà Đen</strong></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Chạm tay vào cột mốc 986 mét</strong></li><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Chiêm bái tại Vườn thiền Ưu Đàm &amp; Tôn tượng Đức Phật Câu Na Hàm Mâu Ni.</strong></li><li style=\"box-sizing: inherit;\">Dạo bước trong&nbsp;<strong style=\"box-sizing: inherit;\">không gian vườn thiền</strong>&nbsp;an yên và tĩnh lặng tại giữa non cao.</li><li style=\"box-sizing: inherit;\">Chiêm bái tôn tượng&nbsp;<strong style=\"box-sizing: inherit;\">Đức Phật Câu Na Hàm Mâu Ni</strong>&nbsp;cao 7,2m bằng đồng đỏ sơn nhũ vàng, tọa trên đài sen giữa hồ sen vàng –&nbsp;<strong style=\"box-sizing: inherit;\">biểu trưng cho cội nguồn trí tuệ, nền tảng giác ngộ và luật nhân quả.</strong></li><li style=\"box-sizing: inherit;\">Chiêm ngưỡng&nbsp;<strong style=\"box-sizing: inherit;\">Thác Ưu Đàm</strong>&nbsp;<strong style=\"box-sizing: inherit;\">hình tròn, đường kính 50m, cao 12m với 32 cột vàng tượng trưng cho 32 tướng tốt của Đức Phật</strong></li><li style=\"box-sizing: inherit;\">Đứng dưới thác nước gởi lời nguyện ước đến<strong style=\"box-sizing: inherit;\">&nbsp;Đại Tượng Phật Di Lặc</strong>&nbsp;được tạo hình theo phương thức đặc biệt:&nbsp;<strong style=\"box-sizing: inherit;\">ghép từ 6.688 viên đá sa thạch tự nhiên theo cảm hứng ruộng bậc thang</strong></li><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Khu trưng bày nghệ thuật Phật Giáo</strong>&nbsp;- chiêm ngưỡng&nbsp;<strong style=\"box-sizing: inherit;\">Xá Lợi Phật, tìm hiểu về vũ trụ trong quan niệm Phật giáo qua các thước phim 3D</strong>, tham quan hàng trăm phiên bản tác phẩm điêu khắc, hội hoa Phật Giáo nổi tiếng trên khắp thế giới</li><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Chiêm bái tượng Phật Bà “Tây Bổ Đà Sơn” bằng đồng trên núi cao nhất Châu Á.</strong></li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Quý khách thưởng thức bữa trưa tại tại&nbsp;<strong style=\"box-sizing: inherit;\">Sun World Ba Den Mountain</strong>.&nbsp;<strong style=\"box-sizing: inherit;\">Trong trường hợp Sun World Ba Den Mountain không phục vụ ăn trưa, Quý khách dùng bữa tại nhà hàng ở Tây Ninh trên đường về.</strong></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Đoàn xuống núi bằng&nbsp;<strong style=\"box-sizing: inherit;\">tuyến cáp treo Vân Sơn</strong>&nbsp;- đưa Quý khách từ đỉnh trở lại chân núi tại Nhà ga Bà Đen.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Trước khi khởi hành về TP.HCM, xe đưa Quý khách tham quan:</p><p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Cơ sở muối Hải:</strong>&nbsp;mua sắm đặc sản được mệnh danh ‘tinh hoa gia vị tại vùng đất Thánh’ như&nbsp;<strong style=\"box-sizing: inherit;\">muối tôm cao cấp, muối trộn bánh tráng, muối tép sấy, muối chay …&nbsp;</strong>góp phần bùng nổ gia vị cùng bánh tráng Tây Ninh.</li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Tạm biệt Tây Ninh, xe đưa Quý khách về điểm đón ban đầu. Kết thúc chương trình du lịch.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">Lưu ý:</strong></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Chương trình của Vietravel là chương trình trọn gói, không được áp dụng chính sách miễn giảm, ưu tiên vào điểm tham quan (nếu có) dành cho trẻ em, người cao tuổi, người có công với cách mạng vì vậy Vietravel sẽ không hoàn lại phần chênh lệch cho các khách hàng thuộc diện ưu tiên này.</strong></li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">(*) Lịch vận hành cáp treo tùy thuộc vào nhà cung cấp dịch vụ</strong></p>',0),(38,5,1,'Yên Minh - Đồng Văn','sáng, trưa,','<p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">5:30:</strong>&nbsp;Xe và Hướng dẫn viên đón Quý khách tại công ty Vietravel (Số 3, Hai Bà Trưng, Hoàn Kiếm, Hà Nội) (Quý khách tự túc ăn sáng). Xe khởi hành đi&nbsp;<strong style=\"box-sizing: inherit;\">Hà Giang</strong>&nbsp;- vùng đất có chè shan, rượu mật ong và thắng cố, xứ sở của đào phai, hoa lê, truyền thống và náo nhiệt trong buổi chợ phiên… Trên đường, Quý khách có thể tranh thủ ngắm cảnh rừng núi Đông bắc vô cùng hùng vĩ và hoang sơ. Và dọc đường đi, xe sẽ dừng nghỉ, Quý khách có thể xuống sẽ thư giãn và chụp hình lưu niệm. Quý khách dừng chân tại&nbsp;<strong style=\"box-sizing: inherit;\">thành phố Hà Giang</strong>&nbsp;để dùng bữa trưa tại nhà hàng - thưởng thức các món ăn đặc sản địa phương như:&nbsp;<em style=\"box-sizing: inherit;\">cá suối, xôi gạo, nếp nương ngũ sắc,...</em></p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Sau đó, Quý khách sẽ đi qua rừng thông bạt ngàn đẹp nhất Việt Nam trải dài trên các sườn núi cao để đến với đến<strong style=\"box-sizing: inherit;\">&nbsp;thị trấn Yên Minh.</strong>&nbsp;Quý khách di chuyển đến địa phận<strong style=\"box-sizing: inherit;\">&nbsp;Huyện Đồng Văn</strong>&nbsp;chiêm ngưỡng vẻ đẹp Cao nguyên đá được UNESCO ghi nhận là công viên địa chất Toàn Cầu vào năm 2010. Quý khách có thể dừng chân thăm quan:</p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Dốc Thẩm Mã</strong>&nbsp;– những con đường đèo khúc khuỷu, quanh co tựa như một dải lụa uốn lượn mềm mại trải dài theo triền núi.</li><li style=\"box-sizing: inherit;\"><strong style=\"box-sizing: inherit;\">Phố Cáo, Sủng Là</strong>, vào làng văn hóa Lũng Cẩm nơi lấy bối cảnh những thước phim nổi tiếng “Chuyện của Pao” - vào mùa đông, mùa xuân nở rộ những đồng hoa cải vàng hoặc hoa đào Tết, quá thích hợp cho những thước hình lãng mạn mà đậm nét văn hóa. Chụp hình giữa vườn hoa mùa xuân bát ngát và thơ mộng.</li></ul><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\">Sau đó đoàn lên xe tiếp tục di chuyển về<strong style=\"box-sizing: inherit;\">&nbsp;Phố Cổ Đồng Văn/ Mèo Vạc</strong>. Quý nhận phòng khách sạn ăn tối tự do khám phá phố cổ Đồng Văn/ Mèo Vạc về đêm.</p><p class=\"ql-align-justify\" style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; text-align: justify; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248);\"><strong style=\"box-sizing: inherit;\">Ngủ đêm tại Đồng Văn/Mèo Vạc</strong></p>',0),(39,1,1,'3463','3643','34634wew',0),(40,1,2,'5t34','3r43','435435werwer',1),(44,6,1,'TP.HCM - Đà Lạt','3','<p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><span style=\"box-sizing: inherit;\">Quý khách tập trung tại&nbsp;<strong style=\"box-sizing: inherit;\">Vietravel</strong>&nbsp;(190 Pasteur, P. Võ Thị Sáu, Q.3, TP.HCM). Đoàn khởi hành đi</span><strong style=\"box-sizing: inherit;\">&nbsp;Đà Lạt.</strong><span style=\"box-sizing: inherit;\">&nbsp;Trên đường, đoàn dừng chân tham quan:</span></span></p><ul style=\"box-sizing: inherit; color: rgb(23, 23, 23); font-family: __Inter_f367f3, __Inter_Fallback_f367f3; font-size: 16px; background-color: rgb(248, 248, 248);\"><li style=\"box-sizing: inherit; text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\"><strong style=\"box-sizing: inherit;\">Thác Bobla:&nbsp;</strong>đẹp như một bức tranh thiên nhiên với dòng thác nguyên sơ, hùng vĩ cao hơn 40m, rộng hơn 20m, cùng cảnh quan được tôn tạo tuyệt đẹp, lưu giữ nhiều cây cổ thụ hàng trăm năm tuổi, phía xa hút tầm mắt là những đồi chè, cà phê xanh mát.</span></li></ul><p style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; line-height: 2.5rem; margin: 1rem; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><span style=\"box-sizing: inherit; font-size: 14px;\">Chiều đoàn tiếp tục hành trình về Đà Lạt, nhận phòng nghỉ ngơi. Buổi tối, Quý khách tự do thưởng thức café ngắm hồ Xuân Hương về đêm.</span></p><div><span style=\"box-sizing: inherit; font-size: 14px;\"><br></span></div><div style=\"box-sizing: inherit; font-family: __Inter_f367f3, __Inter_Fallback_f367f3; color: rgb(23, 23, 23); font-size: 16px; background-color: rgb(248, 248, 248); text-align: justify;\"><div style=\"box-sizing: inherit; font-family: inherit !important;\"></div></div>',0);
